insert into public.messages (id, trip_id, sender_member_id, guest_name, body, thread_date, is_announcement, is_deleted) values ('b93e72a2-f0a5-542f-86f9-8f82e3e7760d', '0039b7b6-fa06-5288-8ab8-bd612320d7f5', 'a1b2c3d4-0001-0001-0001-000000000001', null, 'Tee times are confirmed at Pebble and Spyglass! Check the schedule and make sure your travel is booked. Flight into Monterey (MRY) is closest — book early, it fills up fast.', '2025-07-10', true, false) on conflict (id) do nothing;
